const item = $input.first().json;

let errorMessage = '';
let failedNode = '';
let executionId = '';
let executionUrl = '';
let mode = '';
let workflowName = item.workflow?.name || 'Unknown';
let workflowId = item.workflow?.id || 'Unknown';

if (item.execution) {
  errorMessage = item.execution.error?.message || 'Unknown';
  failedNode = item.execution.lastNodeExecuted || 'Unknown';
  executionId = item.execution.id || 'N/A';
  executionUrl = item.execution.url || 'N/A';
  mode = item.execution.mode || 'Unknown';
} else if (item.trigger) {
  errorMessage = item.trigger.error?.message || 'Unknown';
  failedNode = 'Trigger Node (workflow did not execute)';
  executionId = 'N/A (trigger-level failure)';
  executionUrl = 'N/A (trigger-level failure)';
  mode = item.trigger.mode || 'trigger';
}

// Rate limiting: max 3 email alerts per workflow per 30-minute window
// Bug Log logging is NOT rate-limited — all real errors are always logged
const WINDOW_MS = 30 * 60 * 1000;
const MAX_EMAILS = 3;

const staticData = $getWorkflowStaticData('global');
if (!staticData.emailRateLimits) staticData.emailRateLimits = {};

const now = Date.now();
const limit = staticData.emailRateLimits[workflowId] || { count: 0, windowStart: now };

if (now - limit.windowStart > WINDOW_MS) {
  limit.count = 0;
  limit.windowStart = now;
}

const emailAllowed = limit.count < MAX_EMAILS;
if (emailAllowed) limit.count += 1;
staticData.emailRateLimits[workflowId] = limit;

// Clean stale keys older than 2 windows
for (const k in staticData.emailRateLimits) {
  if (now - staticData.emailRateLimits[k].windowStart > WINDOW_MS * 2) {
    delete staticData.emailRateLimits[k];
  }
}

// Priority classification
const lowPrioritySignals = ['503', '500', '429', 'Service unavailable',
  'Too Many Requests', 'ECONNRESET', 'ETIMEDOUT', 'socket hang up'];
const isLowPriority = lowPrioritySignals.some(s => errorMessage.includes(s));

const priority = isLowPriority ? 'LOW' : 'HIGH';
const priorityLabel = isLowPriority
  ? 'Temporary API/network issue — usually self-resolves'
  : 'Logic or code failure — requires investigation';
const recommendedAction = isLowPriority
  ? 'No action needed — monitor for recurrence. If persistent, check API status.'
  : 'Action required — review execution log. Technical details below.';

return [{
  json: {
    workflowName,
    workflowId,
    errorMessage,
    failedNode,
    executionId,
    executionUrl,
    mode,
    emailAllowed,
    priority,
    priorityLabel,
    recommendedAction
  }
}];
